import{_ as n,j as t,o as g,v as a}from"./chunks/framework.OlxNbC8G.js";const i=JSON.parse('{"title":"Mesage là gì ?","description":"","frontmatter":{"footer":true,"title":"Mesage là gì ?","authors":["lethanh"],"date":"2024-04-015","outline":"deep","draft":true},"headers":[{"level":1,"title":"Message là gì ?","slug":"message-la-gi","link":"#message-la-gi","children":[{"level":2,"title":"Message là gì ?","slug":"message-la-gi-1","link":"#message-la-gi-1","children":[{"level":3,"title":"Tóm gọn Message là gì","slug":"tom-gon-message-la-gi","link":"#tom-gon-message-la-gi","children":[]}]},{"level":2,"title":"Ví dụ về Message","slug":"vi-du-ve-message","link":"#vi-du-ve-message","children":[{"level":3,"title":"Ví dụ 1","slug":"vi-du-1","link":"#vi-du-1","children":[]},{"level":3,"title":"Ví dụ 2","slug":"vi-du-2","link":"#vi-du-2","children":[]}]},{"level":2,"title":"Cách Message  đóng vai trò quan trọng trong việc xây dựng các hệ thống phân phối hiệu quả","slug":"cach-message-đong-vai-tro-quan-trong-trong-viec-xay-dung-cac-he-thong-phan-phoi-hieu-qua","link":"#cach-message-đong-vai-tro-quan-trong-trong-viec-xay-dung-cac-he-thong-phan-phoi-hieu-qua","children":[]},{"level":2,"title":"REF:","slug":"ref","link":"#ref","children":[]}]}],"relativePath":"study/thanhlv-study-2024/2024-04-15-message-la-gi.md","filePath":"study/thanhlv-study-2024/2024-04-15-message-la-gi.md","lastUpdated":1713192513000}'),h={name:"study/thanhlv-study-2024/2024-04-15-message-la-gi.md"},s=[a('<h1 id="message-la-gi" tabindex="-1">Message là gì ? <a class="header-anchor" href="#message-la-gi" aria-label="Permalink to &quot;Message là gì ?&quot;">​</a></h1><p>Mở đầu học về <code>Message and event stream</code> thì mình sẽ giải thích các kiến thức cơ bản trước. Kiến thức đầu tiên là hiểu về <strong>Message</strong>.</p><p><strong>Message</strong> không chỉ là một khái niệm đơn giản; nó là trung tâm của hệ thống, là phương tiện mà dữ liệu di chuyển thông qua giữa các thành phần trong hệ thống.</p><p><strong>Message</strong> không chỉ là một dòng văn bản hay một chuỗi dữ liệu vô nghĩa. Nó mang trên mình một giá trị, một ý nghĩa, và một mục đích. Và điều quan trọng là, nó là cầu nối kết nối giữa các thành phần trong hệ thống, tạo ra một luồng thông tin liên tục và không gián đoạn.</p><p>Hãy cùng mình khám phá sâu hơn về bản chất và ý nghĩa thực sự của Message, và cách nó đóng vai trò quan trọng trong việc xây dựng các hệ thống phân phối hiệu quả. Hãy bắt đầu cuộc hành trình này và khám phá cùng nhau!</p><nav class="table-of-contents"><ul><li><a href="#message-la-gi-1">Message là gì ?</a><ul><li><a href="#tom-gon-message-la-gi">Tóm gọn Message là gì</a></li></ul></li><li><a href="#vi-du-ve-message">Ví dụ về Message</a><ul><li><a href="#vi-du-1">Ví dụ 1</a></li><li><a href="#vi-du-2">Ví dụ 2</a></li></ul></li><li><a href="#cach-message-đong-vai-tro-quan-trong-trong-viec-xay-dung-cac-he-thong-phan-phoi-hieu-qua">Cách Message đóng vai trò quan trọng trong việc xây dựng các hệ thống phân phối hiệu quả</a></li><li><a href="#ref">REF:</a></li></ul></nav><h2 id="message-la-gi-1" tabindex="-1">Message là gì ? <a class="header-anchor" href="#message-la-gi-1" aria-label="Permalink to &quot;Message là gì ?&quot;">​</a></h2><ul><li><p><strong>Đầu tiên</strong>, <strong>Message</strong> là một yêu cầu có chứa một lượng dữ liệu được gửi từ A đến B(Từ hệ thống A đến hệ thống B) và được B nhận và xử lý theo yêu cầu.</p></li><li><p><strong>Thứ hai</strong>, <strong>Message</strong> thường đi kèm với metadata, tức là các thông tin mô tả về Message. Metadata này có thể gồm nhiều thông tin, người gửi, thời gian gửi, người nhận...</p></li><li><p><strong>Thứ ba</strong>, Format của dữ liệu <strong>Message</strong> sẽ là một hợp đồng giữa A và B. hợp đồng này gồm nhiều thứ ví dụ: Định dạng tin nhắn(Json), thuật toán mã hóa, các dữ liệu require trong Json....</p><ul><li>Thông thường Format này sẽ được hệ thống nhận tin nhắn, tức B xác định. Tuy nhiên nhiều trường hợp có thể A xác định và B sẽ làm theo.</li></ul></li><li><p><strong>Thứ tư</strong>, <strong>Message</strong> được mang ý nghĩa giả định người gửi sẽ gửi dữ liệu và sẽ có một người nhận yêu cầu và xử lý yêu cầu. Nếu hành động không được thực hiện tức là đã bi phạm một <strong>business rule</strong> nào đó.</p><ul><li>Thông thường, đây là bước đầu tiên của một quá trình dẫn đến, A nhận được dữ liệu của B, B thay đổi dữ liệu....</li><li></li></ul></li></ul><h3 id="tom-gon-message-la-gi" tabindex="-1"><strong>Tóm gọn Message là gì</strong> <a class="header-anchor" href="#tom-gon-message-la-gi" aria-label="Permalink to &quot;**Tóm gọn Message là gì**&quot;">​</a></h3><ul><li>Message là một yêu cầu thường chứa một khối lượng dữ liệu được chuyển từ một hệ thống sang hệ thống khác để thực hiện các hành động xử lý hoặc trao đổi thông tin.</li></ul><h2 id="vi-du-ve-message" tabindex="-1">Ví dụ về Message <a class="header-anchor" href="#vi-du-ve-message" aria-label="Permalink to &quot;Ví dụ về Message&quot;">​</a></h2><h3 id="vi-du-1" tabindex="-1"><strong>Ví dụ 1</strong> <a class="header-anchor" href="#vi-du-1" aria-label="Permalink to &quot;**Ví dụ 1**&quot;">​</a></h3><p>Application <strong>A</strong> gửi Message đến Application <strong>B</strong> yêu cầu lấy về danh sách học sinh(Tin nhắn được gửi thông qua giao thức <strong>HTTP</strong>).</p><ul><li><ol><li><strong>A</strong> gửi <strong>Message</strong> đến B yều cầu lấy danh sách học sinh thông qua giao thức <strong>HTTP</strong></li></ol></li><li><ol start="2"><li><strong>B</strong> nhận được yêu cầu và kiểm tra đúng các định dạng format của <strong>HTTP</strong> và đúng <strong>business rule</strong>(User ở <strong>A</strong> có quyền đọc...)</li></ol><ul><li>Nếu <strong>A</strong> gửi sai format hoặc vi phạm business rule thì B sẽ từ chối yêu cầu.</li></ul></li><li><ol start="3"><li><strong>B</strong> sử lý yêu cầu và gửi trả lại phản hồi cho <strong>A</strong>.</li></ol></li></ul><h3 id="vi-du-2" tabindex="-1"><strong>Ví dụ 2</strong> <a class="header-anchor" href="#vi-du-2" aria-label="Permalink to &quot;**Ví dụ 2**&quot;">​</a></h3><p>Gửi thư từ nhà của <strong>A</strong> ở <strong>Hà Nội</strong> đến <strong>B</strong> ở <strong>Đà Nẵng</strong> yêu cầu vay 500k VND</p><ul><li><ol><li><strong>A</strong> thực hiện viết Message vào giấy để giở thư đến cho <strong>B</strong>.</li></ol></li><li><ol start="2"><li><strong>A</strong> sẽ sử dụng giao thức gửi thư qua bưu điện vì vậy cần sử dụng <strong>format bao thư</strong> kèm theo <strong>Metadata</strong> người gửi và người nhận.</li></ol></li><li><ol start="3"><li>Sau khi hoàn thành đầy đủ, giao thức bưu điện sẽ gửi thư đến <strong>B</strong> ở <strong>Đà Nẵng</strong>.</li></ol></li><li><ol start="4"><li>Sau khi B nhận thư, tiến hành đọc và xử lý các yêu cầu dựa trên <strong>business rule</strong>( Chơi thân không? Mình có 500k VND không ...)</li></ol></li><li><ol start="5"><li>Nếu thỏa mãn <strong>business rule</strong> B sẽ gửi Message lại đến B với 500K VND họặc không thỏa mãn sẽ gửi lại Message từ chối yêu cầu đến A thông qua giao thức bưu điện.</li></ol></li></ul><h2 id="cach-message-đong-vai-tro-quan-trong-trong-viec-xay-dung-cac-he-thong-phan-phoi-hieu-qua" tabindex="-1">Cách Message đóng vai trò quan trọng trong việc xây dựng các hệ thống phân phối hiệu quả <a class="header-anchor" href="#cach-message-đong-vai-tro-quan-trong-trong-viec-xay-dung-cac-he-thong-phan-phoi-hieu-qua" aria-label="Permalink to &quot;Cách Message  đóng vai trò quan trọng trong việc xây dựng các hệ thống phân phối hiệu quả&quot;">​</a></h2><p>Message đóng vai trò quan trọng trong việc xây dựng các hệ thống phân phối hiệu quả bởi vì nó là phương tiện chính để truyền thông và tương tác giữa các thành phần của hệ thống</p><h2 id="ref" tabindex="-1">REF: <a class="header-anchor" href="#ref" aria-label="Permalink to &quot;REF:&quot;">​</a></h2><ul><li><a href="https://www.rfc-editor.org/rfc/rfc2616.html" target="_blank" rel="noreferrer">https://www.rfc-editor.org/rfc/rfc2616.html</a></li></ul>',21)];const e=n(h,[["render",function(n,a,i,h,e,l){return g(),t("div",null,s)}]]);export{i as __pageData,e as default};
